import type {
  FunctionComponent,
  ReactElement,
  ReactNode,
  MouseEvent,
} from 'react';
import type {
  PolymorphicExoticComponent,
  PolymorphicExoticComponentRestricted,
  WithRef,
} from '@andes/common';
import type { ImageAttributes } from '@andes/image';

type DeprecatedPaddingSize = '0' | '16' | '24' | '32' | '40';

type DeprecatedImage = ImageAttributes;

type ListItemComponentAlternatives = 'div' | 'li';

type PaddingSizes = DeprecatedPaddingSize | 0 | 16 | 24 | 32 | 40;

type RightContentType = {
  /**
   * The content to place on the right.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  content?: string;

  /**
   * Description will only be shown when content is a `String` and `ListItem size !== 'small`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  description?: string;
};

type Sizes = 'large' | 'medium' | 'small';

type ListProps = {
  /**
   * Children of the list element.
   * It must be `<ListItem>` or `<ListGroup>`
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#list | Documentation}
   */
  children?: Array<ReactElement> | ReactElement;

  /**
   * Adds a Custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#list | Documentation}
   */
  className?: string;

  /**
   * List unique Id, used for a11y improvements.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#list | Documentation}
   */
  id?: string;

  /**
   * Whether the items are selectable.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#list | Documentation}
   * @default true
   */
  selectable?: boolean;

  /**
   * Label that describes the list's contents for screen readers.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#list | Documentation}
   */
  srLabel: string;

  /**
   * Defines the type of the list. It can be either `default` or `dropdown`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#list | Documentation}
   * @default 'default'
   */
  type?: 'default' | 'dropdown';

  /**
   * Add a divider between each item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#list | Documentation}
   * @default false
   */
  withDividers?: boolean;
};

type ListGroupSpecificProps = {
  /**
   * Indicates the children of the component.
   * It must be `<ListItem>`
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listgroup | Documentation}
   */
  children: Array<ReactElement> | ReactElement;

  /**
   * Adds a custom class.
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listgroup | Documentation}
   */
  className?: string;

  /**
   * Selectable list unique Id, used for a11y improvements.
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listgroup | Documentation}
   */
  id?: string;

  /**
   * Label to show over the group.
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listgroup | Documentation}
   */
  label: string;

  /**
   * Padding of the group header. It can be `0`, `16`, `24`, `32`, `40`.
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listgroup | Documentation}
   * @default '16'
   */
  paddingSize?: PaddingSizes;

  /**
   * Size of the list item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listgroup | Documentation}
   * @default 'medium'
   */
  size?: Sizes;

  /**
   * Add a divider between each item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listgroup | Documentation}
   * @default false
   */
  withDividers?: boolean;
};

type ListBaseItemSpecificProps = {
  /**
   * Indicates whether the item should be checked.
   */
  checked?: boolean;

  /**
   * Content to be rendered inside the component as its children.
   */
  children?: ReactNode;

  /**
   * Custom class for the component.
   */
  className?: string;

  /**
   * Indicates whether the item should be disabled.
   */
  disabled?: boolean;

  /**
   * Indicates whether the checkbox or radio button should be disabled
   */
  disabledSelection?: boolean;

  /**
   * The property is used to apply alignment styles in the layout when there is a description present.
   */
  hasDescription?: boolean;

  /**
   * The property is used to apply alignment styles in the layout when there is an image on the left side.
   */
  hasLeftContentImage?: boolean;

  /**
   * Indicates whether the list items should have interactive styles.
   */
  interactive?: boolean;

  /**
   * Horizontal padding value for the item.
   */
  paddingSize?: DeprecatedPaddingSize | 0 | 16 | 24 | 32 | 40;

  /**
   * Indicates whether the item should be selected.
   */
  selected?: boolean;

  /**
   * Indicates the size that the item should have.
   *
   * @default 'medium'
   */
  size?: 'large' | 'medium' | 'small';

  /**
   * Indicates whether slot styles should be applied.
   *
   * @default 'false'
   */
  slotted?: boolean;
};

type ListItemContentProps = {
  /**
   * Custom content. It is used only in very specific cases.
   * If title and rightContent are present, it is placed between them.
   */
  children?: ReactNode;

  /**
   * Text or component to display as description.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  description?: ReactNode;

  /**
   * Id of the item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  id?: string;

  /**
   * Node to be shown in the left side.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  leftContent?: DeprecatedImage | ReactNode;

  /**
   * The maximum quantity of lines to display.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  maxLines?: number;

  /**
   * Text or component to display as subcontent information.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  rightContent?: ReactNode | RightContentType;

  /**
   * Position of rightContent. It can be `'top'` or `'centered'`.
   *
   * If an image or Thumbnail is used as leftContent, the position will always be centered.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  rightContentPosition?: 'centered' | 'top';

  /**
   * Size of the list item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   * @default 'medium'
   */
  size?: Sizes;

  /**
   * Text to display as title.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  title?: ReactNode;

  /**
   * Value of the list item (only available when it's used inside a ListBox component).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  value?: string;
};

type ListActionItemProps = {
  children?: ReactNode;

  /**
   * Adds a custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  className?: string;

  /**
   * Text or component to display as description.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  description?: ReactNode;

  /**
   * Whether the item should be disabled.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  disabled?: boolean;

  /**
   * Location where to point the item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  href?: string;

  /**
   * Id of the item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  id?: string;

  /**
   * Node to be shown in the left side.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  leftContent?: DeprecatedImage | ReactNode;

  /**
   * The maximum quantity of lines to display.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  maxLines?: number;

  /**
   * Action to perform when the item is clicked.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  onClick: (event: MouseEvent<HTMLAnchorElement | HTMLButtonElement>) => void;

  /**
   * Padding of the Item. It can be `0`, `16`, `24`, `32`, `40`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   * @default 16
   */
  paddingSize?: PaddingSizes;

  /**
   * Text or component to display as subcontent information.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  rightContent?: ReactNode | RightContentType;

  /**
   * Position of rightContent. It can be `'top'` or `'centered'`.
   *
   * If an image or Thumbnail is used as leftContent, the position will always be centered.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  rightContentPosition?: 'centered' | 'top';

  /**
   * Size of the list item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   * @default 'medium'
   */
  size?: Sizes;

  /**
   * Where to display the provided href. Same as `<a>` attribute target.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  target?: '_blank' | '_parent' | '_self' | '_top';

  /**
   * Text to display as title.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listactionitem | Documentation}
   */
  title?: ReactNode;
};

type ListItemProps = ListItemContentProps & {
  /**
   * Whether the ListItem should have a chevron icon.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   * @default false
   */
  chevron?: boolean;

  /**
   * Custom content. Used only in very specific cases. Use title, description and rightContent to populate the item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  children?: ReactNode;

  /**
   * Adds a custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  className?: string;

  /**
   * Whether the item should be disabled.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   * @default false
   */
  disabled?: boolean;

  /**
   * Location where to point the item.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  href?: string;

  /**
   * Action to perform when the item is clicked.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  onClick?: (
    e: MouseEvent<HTMLAnchorElement | HTMLButtonElement>,
    value: string,
  ) => void;

  /**
   * Padding of the Item. It can be `0`, `16`, `24`, `32`, `40`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   */
  paddingSize?: PaddingSizes;

  /**
   * Whether the item is selected.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   * @default false
   */
  selected?: boolean;

  /**
   * Where to display the provided href. Same as <a> attribute target.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
   * @default false
   */
  target?: '_blank' | '_parent' | '_self' | '_top';
};

type ListBaseItemProps = ListBaseItemSpecificProps & Record<string, unknown>;

type ListGroupProps = ListGroupSpecificProps &
  Record<string, unknown> & {
    component?: 'ol' | 'ul';
  };

/**
 * A collection of styled options.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/992fd4-list/b/26f535 | UI Specs}
 * @example
 * import { List, ListItem } from '@andes/list';
 *
 * const MyComponent = () => (
 *  <List id="telefonos" selectable={false} srLabel="Teléfonos">
 *    <ListItem
 *      description="256gb de memoria"
 *       rightContent={{
 *         content: '$1100',
 *        description: 'Reacondicionado',
 *     }}
 *    title="Iphone 11"
 *    />
 *    <ListItem
 *     description="256gb de memoria"
 *      rightContent={{
 *        content: '$1600',
 *     }}
 *    title="Iphone 12 PRO MAX"
 *    />
 *    <ListItem rightContent="$1800" title="Samsung Galaxy S20" />
 * </List>
 * );
 */
export const List: PolymorphicExoticComponent<'ul', ListProps>;

/**
 * A collection of styled options.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/992fd4-list/b/26f535 | UI Specs}
 * @example
 * import { List, ListActionItem } from '@andes/list';
 *
 * const MyComponent = () => (
 *  <List srLabel="Teléfonos">
 *    <ListActionItem srLabel="Iphone 11" title="Iphone 11" onClick={handleClick} />
 *    <ListActionItem srLabel="Iphone 12 PRO MAX" title="Iphone 12 PRO MAX" onClick={handleClick} />
 *    <ListActionItem srLabel="Samsung Galaxy S20" title="Samsung Galaxy S20" onClick={handleClick} />
 * </List>
 * );
 */
export const ListActionItem: PolymorphicExoticComponentRestricted<
  'li',
  ListActionItemProps,
  ListItemComponentAlternatives
>;

export const ListBaseItem: PolymorphicExoticComponentRestricted<
  'li',
  ListBaseItemProps,
  ListItemComponentAlternatives
> &
  WithRef<HTMLLIElement>;

/**
 * Groups List Items.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listgroup | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/992fd4-list/b/26f535 | UI Specs}
 * @example
 * import { List, ListGroup, ListItem } from '@andes/list';
 *
 * const MyComponent = () => (
 *  <List id="medios-de-pago" selectable={false} srLabel="Medios de pago">
 *    <ListGroup label="Tarjetas de crédito">
 *      <ListItem description="Todos los bancos" title="Visa" />
 *      <ListItem description="Banco Nación" title="Mastercard" />
 *    </ListGroup>
 *    <ListGroup label="Tarjetas de débito">
 *      <ListItem description="Todos los bancos" title="Visa" />
 *      <ListItem description="Todos los bancos" title="American Express" />
 *    </ListGroup>
 *  </List>
 *);
 */
export const ListGroup: FunctionComponent<ListGroupProps>;

/**
 * List item.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/list#listitem | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/992fd4-list/b/26f535 | UI Specs}
 * @example
 * import { List, ListItem } from '@andes/list';
 *
 *  const MyComponent = () => (
 *    <List id="categorias" srLabel="Categorías">
 *     <ListItem
 *      chevron
 *      disabled
 *      href="https://www.mercadolibre.com.ar/vehiculos"
 *      title="Vehículos"
 *     />
 *    <ListItem
 *     chevron
 *     href="https://www.mercadolibre.com.ar/inmuebles"
 *     target="_blank"
 *     title="Inmuebles"
 *    />
 * </List>
 *);
 */
export const ListItem: PolymorphicExoticComponentRestricted<
  'li',
  ListItemProps,
  ListItemComponentAlternatives
>;

export const ListItemContent: FunctionComponent<ListItemContentProps>;

export type ImageContent = DeprecatedImage;
export type RightContent = RightContentType;
